/* Check / X / Partial icons */
function FeatureIcon({ value }) {
  if (value === true) return (
    <span className={s.featureCheck}>&#10003;</span>
  )
  if (value === 'partial') return (
    <span className={s.featurePartial}>Partial</span>
  )
  return (
    <span className={s.featureX}>&times;</span>
  )
}

/* Feature comparison table */
function ComparisonTable({ competitor }) {
  let currentCategory = ''
  return (
    <div className={s.tableWrap}>
      <table className={s.table}>
        <thead>
          <tr>
            <th className={s.tableHeaderFeature}>Feature</th>
            <th className={s.tableHeaderAura}>Aura Alpha</th>
            <th className={s.tableHeaderComp}>{competitor.name}</th>
          </tr>
        </thead>
        <tbody>
          {FEATURE_CATEGORIES.map((feat) => {
            const showCategory = feat.category !== currentCategory
            if (showCategory) currentCategory = feat.category
            return (
              <tr key={feat.key}>
                <td className={showCategory ? s.tableCellCategory : s.tableCell}>
                  {showCategory && (
                    <div className={s.categoryLabel}>{feat.category}</div>
                  )}
                  {feat.label}
                </td>
                <td className={s.tableCellAura}>
                  <FeatureIcon value={AURA_FEATURES[feat.key]} />
                </td>
                <td className={s.tableCellCenter}>
                  <FeatureIcon value={competitor.features[feat.key]} />
                </td>
              </tr>
            )
          })}
        </tbody>
      </table>
    </div>
  )
}

